if __name__ == '__main__':
    existing = load_synthesis('romans')
    merge_synthesis(existing, NEW_DATA)
    save_synthesis('romans', existing)

    import json, pathlib
    ROOT = pathlib.Path(__file__).parent.parent
    il = json.loads((ROOT / 'data' / 'interlinear' / 'romans.json').read_text())
    syn = json.loads((ROOT / 'data' / 'commentary' / 'synthesis' / 'romans.json').read_text())
    for ch_str, expected in [('11', 36)]:
        il_vv = set(il.get(ch_str, {}).keys())
        syn_vv = set(syn.get(ch_str, {}).keys())
        missing = il_vv - syn_vv
        status = f'MISSING {sorted(missing, key=int)}' if missing else 'OK'
        print(f'  Romans {ch_str}: {len(syn_vv)}/{expected} verses — {status}')
